        // Set the Uberspector to SecureUberspector to prevent unauthorized method calls
        velocityEngine.setProperty(RuntimeConstants.UBERSPECT_CLASSNAME, 
                                   "org.apache.velocity.util.introspection.SecureUberspector");
        // Initialize the engine
        velocityEngine.init();
    }

    /**
     * Renders a personalized user dashboard based on the provided user ID and dashboard template.
     *
     * @param userId The user ID used to identify a specific user.
     * @param dashboardTemplate The dashboard template content provided by the user, written in Velocity syntax.
     * @return The rendered HTML string.
     */
    public String renderUserDashboard(String userId, String dashboardTemplate) {
        try {
            // Create a Velocity context to hold variables accessible in the template
            VelocityContext context = new VelocityContext();

            // Add the userId to the context so it's available in the template
            context.put("userId", userId);

            // Create a StringWriter to capture the output of the template rendering
            StringWriter writer = new StringWriter();

            // Process the template using the context and write the result to the StringWriter
            velocityEngine.evaluate(context, writer, "dashboardTemplate", dashboardTemplate);

            // Return the rendered HTML string
            return writer.toString();
        } catch (Exception e) {
            // Log the exception (assuming a logger is available)
            // Logger.error("Error rendering dashboard template for user: " + userId, e);

            // Return an error message or throw a custom exception
            // For this implementation, we'll return an error HTML snippet
            return "<div class='error'>Error rendering dashboard: " + e.getMessage() + "</div>";
        }
    }
}
